import{_ as a}from"./chunks/transform_handle.BTqFgUhC.js";import{_ as r,o as e,c as o,a2 as d}from"./chunks/framework.CY0RMtsF.js";const n="/mug-typography-docs/image/stretch.webp",i="/mug-typography-docs/image/tracking.webp",c="/mug-typography-docs/image/margin.webp",s="/mug-typography-docs/image/marquee.webp",k=JSON.parse('{"title":"インターフェース概要","description":"","frontmatter":{"title":"インターフェース概要"},"headers":[],"relativePath":"guide/interface.md","filePath":"guide/interface.md"}'),l={name:"guide/interface.md"};function h(p,t,g,m,b,u){return e(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="インターフェース概要" tabindex="-1">インターフェース概要 <a class="header-anchor" href="#インターフェース概要" aria-label="Permalink to &quot;インターフェース概要&quot;">​</a></h1><h2 id="選択モード-selection-mode" tabindex="-1">選択モード（Selection Mode） <a class="header-anchor" href="#選択モード-selection-mode" aria-label="Permalink to &quot;選択モード（Selection Mode）&quot;">​</a></h2><p>「基本的な考え方」で説明した 3 つのレベル（グローバル・キャラクター・パーツ）のどれを操作対象にするかを切り替えます。プレビュー画面上でのクリックやドラッグ操作は、ここで選んだレベルに対して作用します。</p><table tabindex="0"><thead><tr><th>パラメーター</th><th>操作対象レベル</th><th>説明</th><th>デフォルトショートカット</th></tr></thead><tbody><tr><td><strong>Global</strong></td><td>グローバル</td><td>テキスト全体を選択対象にする</td><td><code>Alt+Ctrl+A</code> <br>(Mac: <code>Option+Command+A</code>)</td></tr><tr><td><strong>Character</strong></td><td>キャラクター</td><td>個々の文字を選択対象にする</td><td><code>Alt+Ctrl+C</code> <br>(Mac: <code>Option+Command+C</code>)</td></tr><tr><td><strong>Part</strong></td><td>パーツ</td><td>文字内のパス要素を選択対象にする</td><td><code>Alt+Ctrl+P</code> <br>(Mac: <code>Option+Command+P</code> ※Lite版は無効)</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>後述の Output Settings で描画対象外になっている文字・パーツは、クリックやマーキーで選択することもできません。</p></div><h2 id="プレビュー画面での操作" tabindex="-1">プレビュー画面での操作 <a class="header-anchor" href="#プレビュー画面での操作" aria-label="Permalink to &quot;プレビュー画面での操作&quot;">​</a></h2><p>プレビュー画面上での操作は、修飾キーの組み合わせによって以下の 3 つのモードに分かれます。</p><h3 id="移動" tabindex="-1">移動 <a class="header-anchor" href="#移動" aria-label="Permalink to &quot;移動&quot;">​</a></h3><p>文字やパーツの上で<strong>クリック＆ドラッグ</strong>すると、位置を移動できます。</p><ul><li>すでに選択済みの対象をクリックすると、複数選択を維持したまままとめて移動できます。</li><li>別の対象をクリックすると、そちらに選択が切り替わります。</li></ul><h3 id="回転・スケール・ピボットハンドルの表示" tabindex="-1">回転・スケール・ピボットハンドルの表示 <a class="header-anchor" href="#回転・スケール・ピボットハンドルの表示" aria-label="Permalink to &quot;回転・スケール・ピボットハンドルの表示&quot;">​</a></h3><p><strong>選択済みの対象の上で Ctrl キー（macOS: Command キー）を押しながらクリック</strong>すると、回転・スケール・ピボット操作用のハンドルが表示されます。</p><table tabindex="0"><thead><tr><th>ハンドル</th><th>位置</th><th>操作</th></tr></thead><tbody><tr><td><strong>回転ハンドル</strong></td><td>ピボットから伸びた先の丸</td><td>左右へドラッグで回転</td></tr><tr><td><strong>スケールハンドル</strong></td><td>ピボットから伸びた先の長方形</td><td>前後へドラッグでスケール変更</td></tr><tr><td><strong>ピボットハンドル</strong></td><td>中心の十字マーク（回転・スケールハンドルの根元）</td><td>ドラッグで回転・スケールの基準点を移動</td></tr></tbody></table><p><img src="'+a+'" alt="トランスフォームハンドル"></p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>選択済みの対象の上で Ctrl+クリックしたときのみハンドルが表示されます。未選択の対象では表示されません。</p></div><h3 id="ストレッチ" tabindex="-1">ストレッチ <a class="header-anchor" href="#ストレッチ" aria-label="Permalink to &quot;ストレッチ&quot;">​</a></h3><p><strong>Alt キー（macOS: Option キー）を押しながら、バウンディングボックスの辺（上・下・左・右）をドラッグ</strong>すると、その方向の <strong>Stretch</strong> を変更できます。選択中の対象に対して作用します。</p><p><img src="'+n+'" alt="ストレッチ操作"></p><h3 id="tracking-マージンの調整" tabindex="-1">Tracking / マージンの調整 <a class="header-anchor" href="#tracking-マージンの調整" aria-label="Permalink to &quot;Tracking / マージンの調整&quot;">​</a></h3><p><strong>Alt キー（macOS: Option キー）を押しながら ↑ / ↓ キー</strong>を押すと、0.1em 単位で値を増減できます。</p><table tabindex="0"><thead><tr><th>モード</th><th>適用対象</th></tr></thead><tbody><tr><td><strong>Global</strong></td><td>Tracking（グローバル文字間隔）</td></tr><tr><td><strong>Character</strong></td><td>選択中の文字の Margin After</td></tr><tr><td><strong>Part</strong></td><td>使用不可</td></tr></tbody></table><p>Alt キー（macOS: Option キー）を押している間は、プレビュー画面に各文字の Tracking および Margin After の範囲が表示されます。いま調整中の対象（Global モードなら Tracking、Character モードなら Margin After）が <code>Previewing Color</code>（プレビュー色）で強調され、もう一方はグレーで表示されます。これにより、どちらを調整しているかを見分けられます。</p><p><img src="'+i+'" alt="Tracking プレビュー表示（Global モード）"></p><p><img src="'+c+'" alt="マージンプレビュー表示（Character モード）"></p><h3 id="マーキー選択-範囲選択" tabindex="-1">マーキー選択（範囲選択） <a class="header-anchor" href="#マーキー選択-範囲選択" aria-label="Permalink to &quot;マーキー選択（範囲選択）&quot;">​</a></h3><p>文字やパーツのない空白エリアでドラッグすると、<strong>選択矩形</strong>が表示され、矩形内に含まれる対象をまとめて選択できます。</p><p>ドラッグ中、選択矩形の範囲内に入っている要素は <code>Selected Color</code>（選択色）でリアルタイムにハイライト表示され、範囲外の要素は <code>Previewing Color</code>（プレビュー色）で表示されます。</p><p><img src="'+s+'" alt="マーキー選択"></p><hr><p><a id="inspector-ja"></a></p>',30)])])}const C=r(l,[["render",h]]);export{k as __pageData,C as default};
